pragma solidity ^0.8.20;

contract MembershipAirdrop {
    address private _owner;
    mapping(address => uint256) public tierOf;
    mapping(address => bool) public claimed;
    mapping(address => uint256) public airdropCredits;
    mapping(address => uint256) public purchasedTokens;

    event TierSet(address indexed user, uint256 tier);
    event AirdropClaimed(address indexed user, uint256 credits);
    event TokensPurchased(address indexed user, uint256 amount);
    event Withdrawn(uint256 amount);

    bool private _locked;

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    modifier nonReentrant() {
        require(!_locked, "ReentrancyGuard: reentrant call");
        _locked = true;
        _;
        _locked = false;
    }

    constructor() {
        _owner = msg.sender;
    }

    function setTier(address user, uint256 tier) external onlyOwner {
        tierOf[user] = tier;
        emit TierSet(user, tier);
    }

    function claimAirdrop() external {
        require(tierOf[msg.sender] > 0, "No tier");
        require(!claimed[msg.sender], "Already claimed");
        uint256 credits = tierOf[msg.sender] * 100;
        airdropCredits[msg.sender] += credits;
        claimed[msg.sender] = true;
        emit AirdropClaimed(msg.sender, credits);
    }

    function purchaseTokens() external payable {
        require(msg.value > 0, "Zero value");
        require(tierOf[msg.sender] > 0, "No tier");
        uint256 tokens = (msg.value * 1000) / 1 ether;
        purchasedTokens[msg.sender] += tokens;
        emit TokensPurchased(msg.sender, tokens);
    }

    function withdrawAll() external onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        (bool sent, ) = _owner.call{value: balance}("");
        require(sent, "Failed to send Ether");
        emit Withdrawn(balance);
    }
}
